(self.webpackChunk=self.webpackChunk||[]).push([[448],{9692:(t,e,l)=>{"use strict";l.r(e),l.d(e,{data:()=>r});const r={key:"v-4528a075",path:"/tools/intellij.html",title:"intellij使用",lang:"en-US",frontmatter:{title:"intellij使用"},excerpt:"",headers:[{level:2,title:"配置lombok",slug:"配置lombok",children:[]},{level:2,title:"Jrebel 插件破解",slug:"jrebel-插件破解",children:[]},{level:2,title:"快捷键",slug:"快捷键",children:[{level:3,title:"1.编辑",slug:"_1-编辑",children:[]},{level:3,title:"2.查找或替换",slug:"_2-查找或替换",children:[]},{level:3,title:"3.查看使用情况",slug:"_3-查看使用情况",children:[]},{level:3,title:"4.编译与运行",slug:"_4-编译与运行",children:[]},{level:3,title:"5.调试",slug:"_5-调试",children:[]},{level:3,title:"6.导航",slug:"_6-导航",children:[]}]}],filePathRelative:"tools/intellij.md",git:{updatedTime:1626154667e3,contributors:[]}}},8884:(t,e,l)=>{"use strict";l.r(e),l.d(e,{default:()=>f});var r=l(6252);const n=(0,r.Wm)("h2",{id:"配置lombok",tabindex:"-1"},[(0,r.Wm)("a",{class:"header-anchor",href:"#配置lombok","aria-hidden":"true"},"#"),(0,r.Uk)(" 配置lombok")],-1),d=(0,r.Wm)("ul",null,[(0,r.Wm)("li",null,"Settings--\x3ePlugins--\x3e安装lombok插件"),(0,r.Wm)("li",null,[(0,r.Uk)("Settings--\x3eBuild，Execution，Deployment--\x3eCompiler--\x3eAnnotation Processors--\x3eEnable annotation processing"),(0,r.Wm)("br"),(0,r.Wm)("br"),(0,r.Wm)("br")])],-1),s=(0,r.Wm)("h2",{id:"jrebel-插件破解",tabindex:"-1"},[(0,r.Wm)("a",{class:"header-anchor",href:"#jrebel-插件破解","aria-hidden":"true"},"#"),(0,r.Uk)(" Jrebel 插件破解")],-1),a=(0,r.Uk)("大神基于JAVA写了一个可用于jrebel激活及jetbrains激活的服务器，详见 "),i={href:"https://gitee.com/gsls200808/JrebelLicenseServerforJava",target:"_blank",rel:"noopener noreferrer"},c=(0,r.Uk)("https://gitee.com/gsls200808/JrebelLicenseServerforJava"),g=(0,r.Uk)("本人基于知名容器服务商"),o=(0,r.Wm)("strong",null,"kintohub",-1),y=(0,r.Uk)("搭建了一套环境供使用，地址为："),x={href:"https://jrebel.ran-ding.cf",target:"_blank",rel:"noopener noreferrer"},p=(0,r.Uk)("jrebel.ran-ding.cf"),h=(0,r.uE)('<p>注意按提示，但不要加端口号，因涉及过了一次docker服务的端口映射，页面上的<em>8081</em>端口不需要加</p><h2 id="快捷键" tabindex="-1"><a class="header-anchor" href="#快捷键" aria-hidden="true">#</a> 快捷键</h2><h3 id="_1-编辑" tabindex="-1"><a class="header-anchor" href="#_1-编辑" aria-hidden="true">#</a> 1.编辑</h3><table><thead><tr><th style="text-align:center;">快捷键</th><th style="text-align:center;">中文说明</th></tr></thead><tbody><tr><td style="text-align:center;">Ctrl + Space</td><td style="text-align:center;">补全代码，由于经常与操作系统的输入法的切换冲突，所以实际很少用。一般直接在 idea 中开启输入自动补全机制。</td></tr><tr><td style="text-align:center;">Ctrl + Shift + Space</td><td style="text-align:center;">在列出的可选项中只显示出你所输入的关键字最相关的信息。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + ↑/↓</td><td style="text-align:center;">代码向上下移动一行 <span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Alt + V</td><td style="text-align:center;">自动返回对象 <span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + Enter</td><td style="text-align:center;">代码补全后，自动在代码末尾添加分号结束符</td></tr><tr><td style="text-align:center;">Ctrl + P</td><td style="text-align:center;">在某个方法中，调用该按键后，会展示出这个方法的调用参数列表信息。</td></tr><tr><td style="text-align:center;">Ctrl + Q</td><td style="text-align:center;">展示某个类或者方法的 API 说明文档</td></tr><tr><td style="text-align:center;">Ctrl + mouse</td><td style="text-align:center;">跳进到某个类或者方法源代码中进行查看。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Alt + Insert</td><td style="text-align:center;">自动生成某个类的 Getters, Setters, Constructors, hashCode/equals, toString 等代码。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + O</td><td style="text-align:center;">展示该类中所有覆盖或者实现的方法列表，注意这里是字母小写的 O！</td></tr><tr><td style="text-align:center;">Ctrl + Alt + T</td><td style="text-align:center;">自动生成具有环绕性质的代码，比如：if…else,try…catch, for, synchronized 等等，使用前要先选择好需要环绕的代码块。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + /</td><td style="text-align:center;">对单行代码，添加或删除注释。分为两种情况：如果只是光标停留在某行，那么连续使用该快捷键，会不断注释掉下一行的代码；如果选定了某行代码（选定了某行代码一部分也算这种情况），那么连续使用该快捷键，会在添加或删除该行注释之间来回切换。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + /</td><td style="text-align:center;">对代码块，添加或删除注释。它与 Ctrl + / 的区别是，它只会在代码块的开头与结尾添加注释符号！<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + W</td><td style="text-align:center;">选中当前光标所在的代码块，多次触发，代码块会逐级变大。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + W</td><td style="text-align:center;">是 Ctrl + W 的反向操作，多次触发，代码块会逐级变小，最小变为光标。</td></tr><tr><td style="text-align:center;">Alt + Q</td><td style="text-align:center;">展示包含当前光标所在代码的父节点信息，比如在 java 方法中调用，就会展示方法签名信息。</td></tr><tr><td style="text-align:center;">Alt + Enter</td><td style="text-align:center;">展示当前当前光标所在代码，可以变化的扩展操作</td></tr><tr><td style="text-align:center;">Ctrl + Alt + L</td><td style="text-align:center;">格式化代码 <span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Alt + O</td><td style="text-align:center;">去除没有实际用到的包，这在 java 类中特别有用。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Alt + I</td><td style="text-align:center;">按照缩进的设定，自动缩进所选择的代码段。</td></tr><tr><td style="text-align:center;">Tab / Shift + Tab</td><td style="text-align:center;">缩进或者不缩进一次所选择的代码段。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + X 或 Shift Delete</td><td style="text-align:center;">剪切当前代码。 <span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + C 或 Ctrl + Insert</td><td style="text-align:center;">拷贝当前代码。 <span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + V 或 Shift + Insert</td><td style="text-align:center;">粘贴之前剪切或拷贝的代码。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + V</td><td style="text-align:center;">从之前的剪切或拷贝的代码历史记录中，选择现在需要粘贴的内容。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + D</td><td style="text-align:center;">复制当前选中的代码。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Y</td><td style="text-align:center;">删除当前光标所在的代码行。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + J</td><td style="text-align:center;">把下一行的代码接续到当前的代码行。</td></tr><tr><td style="text-align:center;">Ctrl + Enter</td><td style="text-align:center;">当前代码行与下一行代码之间插入一个空行，原来所在的光标不变。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Shift + Enter</td><td style="text-align:center;">当前代码行与下一行代码之间插入一个空行，原来光标现在处于新加的空行上。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + U</td><td style="text-align:center;">所选择的内容进行大小写转换。。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + ]/[</td><td style="text-align:center;">从当前光标所在位置开始，一直选择到当前光标所在代码段起始或者结束位置。</td></tr><tr><td style="text-align:center;">Ctrl + Delete</td><td style="text-align:center;">删除从当前光标所在位置开始，直到这个单词的结尾的内容。</td></tr><tr><td style="text-align:center;">Ctrl + NumPad(+/-)</td><td style="text-align:center;">展开或收缩代码段。 <span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + NumPad(+)</td><td style="text-align:center;">展开所有代码段。</td></tr><tr><td style="text-align:center;">Ctrl + Shift + NumPad(-)</td><td style="text-align:center;">收缩所有代码段。</td></tr><tr><td style="text-align:center;">Ctrl + F4</td><td style="text-align:center;">关闭当前标签页。</td></tr><tr><td style="text-align:center;">Shift + F6</td><td style="text-align:center;">修改名字。<span style="color:red;"><strong>（常用）</strong></span></td></tr></tbody></table><blockquote><p>1.1 Ctrl + Shift + Space 示例（智能补全）</p></blockquote><p>使用前，用于补全的列表，默认是以输入的关键字作为前缀的： <img src="/intellij/1589726253134.jfif" alt=""> 使用后，用于补全的列表，会把与输入的关键字最相关的信息排到最前面，比如这里的 Resource 的实现类会直接过滤出来，很方便吧 O(∩_∩)O~： <img src="/intellij/1589726265866.jfif" alt=""></p><blockquote><p>1.2 Ctrl + P 示例（方法参数列表）</p></blockquote><p><img src="/intellij/1589726288856.jfif" alt=""></p><blockquote><p>1.3 Ctrl + Q 示例（API 说明文档）</p></blockquote><p><img src="/intellij/1589726310129.jfif" alt=""> 不大好用，字体太小了，还不如直接 [ctrl + 点击] 看源代码来的方便！</p><blockquote><p>1.4 Alt + Insert 示例（自动生成与类相关的代码）</p></blockquote><p>如果绑定了 Spring 框架，还能自动生成与 Spring 相关的依赖参数哦： <img src="/intellij/1589726375820.jfif" alt=""></p><blockquote><p>1.5 Ctrl + O 示例（该类中所有覆盖或者实现的方法列表）</p></blockquote><p><img src="/intellij/1589726401798.jfif" alt=""></p><blockquote><p>1.6 Ctrl + Alt + T 示例（生成具有环绕性质的代码）</p></blockquote><p><img src="/intellij/1589726426423.jfif" alt=""> 在右边的 Surround with 列表，就是目前支持的自动代码环绕功能，可以直接通过列表最左边的快捷键选择，是不是很方便呀 O(∩_∩)O~</p><p>它还支持自定义的代码模板（Live templates）呢，很强大吧。</p><blockquote><p>1.7 Ctrl + Shift + V 示例（剪切或拷贝的代码历史记录中，选择粘贴的内容）</p></blockquote><p>这是一个很酷的功能 O(∩_∩)O~，它会把之前剪切或拷贝的代码历史记录（最近 5 条）展示出来，让你来选择哦。可惜的是，列表选项如果是中文会乱码，还好内容可以正常显示： <img src="/intellij/1589726532155.jfif" alt=""></p><h3 id="_2-查找或替换" tabindex="-1"><a class="header-anchor" href="#_2-查找或替换" aria-hidden="true">#</a> 2.查找或替换</h3><table><thead><tr><th style="text-align:center;">快捷键</th><th style="text-align:center;">中文说明</th></tr></thead><tbody><tr><td style="text-align:center;">Ctrl + F</td><td style="text-align:center;">在当前标签页中进行查找，还支持正则表达式哦。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">F3</td><td style="text-align:center;">如果找到了多个查找结果，每调用一次就会跳到下一个结果，很方便哦。</td></tr><tr><td style="text-align:center;">Shift + F3</td><td style="text-align:center;">是 F3 的反向操作，即每调用一次就会跳到上一个结果。</td></tr><tr><td style="text-align:center;">Ctrl + R</td><td style="text-align:center;">在当前标签页中进行替换操作。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + F</td><td style="text-align:center;">通过路径查找。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + R</td><td style="text-align:center;">通过路径替换。<span style="color:red;"><strong>（常用）</strong></span></td></tr></tbody></table><blockquote><p>2.1 Ctrl + F （查找）</p></blockquote><p>触发后，会打开一个查找面板： <img src="/intellij/1589726587651.jfif" alt=""> 触发后，会打开一个查找面板：</p><table><thead><tr><th style="text-align:center;">图示</th><th style="text-align:center;">说明</th></tr></thead><tbody><tr><td style="text-align:center;">向上箭头</td><td style="text-align:center;">就是 快捷键【Shift + F3】，每调用一次就会跳到上一个结果。</td></tr><tr><td style="text-align:center;">向下箭头</td><td style="text-align:center;">就是 快捷键【F3】，每调用一次就会跳到下一个结果。</td></tr><tr><td style="text-align:center;">加号符号</td><td style="text-align:center;">把当前的高亮项加入到选中的列表中。</td></tr><tr><td style="text-align:center;">减号符号</td><td style="text-align:center;">把当前的高亮项从选中的列表中移除。</td></tr><tr><td style="text-align:center;">勾选符号</td><td style="text-align:center;">把所有的查找结果同时选中，这很适合批量操作。</td></tr><tr><td style="text-align:center;">文本内的向上箭头</td><td style="text-align:center;">打开查询结果列表面板。</td></tr><tr><td style="text-align:center;">两个框加一个向下箭头</td><td style="text-align:center;">更多选项。</td></tr><tr><td style="text-align:center;">Match Case</td><td style="text-align:center;">是否大小写敏感。</td></tr><tr><td style="text-align:center;">Regex</td><td style="text-align:center;">正则表达式。</td></tr><tr><td style="text-align:center;">Words</td><td style="text-align:center;">匹配单词。</td></tr><tr><td style="text-align:center;">x matches</td><td style="text-align:center;">x 表示的是找到的记录数。</td></tr><tr><td style="text-align:center;">勾选符号选中效果：</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;"><img src="/intellij/1589726755686.jfif" alt=""></td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">点击文本内的向上箭头，打开后的查询结果列表面板：</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;"><img src="/intellij/1589726765627.jfif" alt=""></td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">两个框加一个向下箭头，会变成一个大文本输入框，而且还多出一个查看搜索历史的按钮：</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;"><img src="/intellij/1589726785858.jfif" alt=""></td><td style="text-align:center;"></td></tr></tbody></table><blockquote><p>2.2 Ctrl + Shift + F （通过路径查找）</p></blockquote><p><img src="/intellij/1589726804498.jfif" alt=""></p><h3 id="_3-查看使用情况" tabindex="-1"><a class="header-anchor" href="#_3-查看使用情况" aria-hidden="true">#</a> 3.查看使用情况</h3><table><thead><tr><th style="text-align:center;">快捷键</th><th style="text-align:center;">中文说明</th></tr></thead><tbody><tr><td style="text-align:center;">Alt + F7</td><td style="text-align:center;">在当前项目中的使用情况，会打开一个使用情况面板。</td></tr><tr><td style="text-align:center;">Ctrl + F7</td><td style="text-align:center;">在当前文件中的使用情况，找的内容会低亮显示。</td></tr><tr><td style="text-align:center;">Ctrl + Shift + F7</td><td style="text-align:center;">在当前文件中的使用情况，找的内容会高亮显示。</td></tr><tr><td style="text-align:center;">Ctrl + Alt + F7</td><td style="text-align:center;">打开使用情况列表。 <span style="color:red;"><strong>（常用）</strong></span></td></tr></tbody></table><blockquote><p>3.1 Ctrl + Alt + F7（打开使用情况列表） <img src="/intellij/1589726830701.jfif" alt=""></p></blockquote><h3 id="_4-编译与运行" tabindex="-1"><a class="header-anchor" href="#_4-编译与运行" aria-hidden="true">#</a> 4.编译与运行</h3><table><thead><tr><th style="text-align:center;">快捷键</th><th style="text-align:center;">中文说明</th></tr></thead><tbody><tr><td style="text-align:center;">Ctrl + F9 Make project</td><td style="text-align:center;">编译项目（如果之前有编译过，那么只会编译那些修改的类或者依赖的包）。</td></tr><tr><td style="text-align:center;">Ctrl + Shift + F9</td><td style="text-align:center;">编译所中的范围（如果在某个类中，那么只会编译当前类）。</td></tr><tr><td style="text-align:center;">Alt + Shift + F10</td><td style="text-align:center;">会打开一个已经配置的运行列表，让你选择一个后，再运行。</td></tr><tr><td style="text-align:center;">Alt + Shift + F9</td><td style="text-align:center;">会打开一个已经配置的运行列表，让你选择一个后，再以调试模式运行。</td></tr><tr><td style="text-align:center;">Shift + F10</td><td style="text-align:center;">立即运行当前配置的运行实例，这个在单元测试中特别好用。 <span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Shift + F9</td><td style="text-align:center;">立即以编译模式运行当前配置的运行实例。</td></tr><tr><td style="text-align:center;">Ctrl + Shift + F10</td><td style="text-align:center;">按照编辑器绑定的文件类型，运行相关的程序。比如一个 html 页面，调用后，会直接打开一个浏览器。</td></tr></tbody></table><blockquote><p>4.1 Alt + Shift + F10（打开运行列表，选择一个运行）</p></blockquote><p><img src="/intellij/1589726858431.jfif" alt=""></p><h3 id="_5-调试" tabindex="-1"><a class="header-anchor" href="#_5-调试" aria-hidden="true">#</a> 5.调试</h3><table><thead><tr><th style="text-align:center;">快捷键</th><th style="text-align:center;">中文说明</th></tr></thead><tbody><tr><td style="text-align:center;">F8</td><td style="text-align:center;">跳到当前代码下一行。 <span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">F7</td><td style="text-align:center;">跳入到调用的方法内部代码。 <span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Shift + F7</td><td style="text-align:center;">会打开一个面板，让你选择具体要跳入的类方法，这个在复杂的嵌套代码中特别有用。</td></tr><tr><td style="text-align:center;">Shift + F8</td><td style="text-align:center;">跳出当前的类，到上一级。 <span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Alt + F9</td><td style="text-align:center;">让代码运行到当前光标所在处，非常棒的功能。 <span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Alt + F8</td><td style="text-align:center;">打开一个表达式面板，然后进行进一步的计算。</td></tr><tr><td style="text-align:center;">F9</td><td style="text-align:center;">结束当前断点的本轮调试（因为有可能代码会被调用多次，所以调用后只会结束当前的这一次）；如果有下一个断点会跳到下一个断点中。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + F8</td><td style="text-align:center;">在当前光标处，添加或者删除断点。</td></tr><tr><td style="text-align:center;">Ctrl + Shift + F8</td><td style="text-align:center;">打开当前断点的面板，可以进行条件过滤哦。</td></tr></tbody></table><blockquote><p>5.1 Shift + F7（选择具体要跳入的类方法）</p></blockquote><p><img src="/intellij/1589726893980.jfif" alt=""></p><blockquote><p>5.2 Alt + F8 （计算表达式）</p></blockquote><p>注意：要在当前断点之前的代码中，选择某一个变量运行才有效，因为只有代码运行过了，才会有值的呀 O(∩_∩)O~ <img src="/intellij/1589726919299.jfif" alt=""></p><blockquote><p>5.3 Ctrl + Shift + F8 （当前断点的面板）</p></blockquote><p><img src="/intellij/1589726942178.jfif" alt=""></p><h3 id="_6-导航" tabindex="-1"><a class="header-anchor" href="#_6-导航" aria-hidden="true">#</a> 6.导航</h3><table><thead><tr><th style="text-align:center;">快捷键</th><th style="text-align:center;">中文说明</th></tr></thead><tbody><tr><td style="text-align:center;">Ctrl + N</td><td style="text-align:center;">打开类查询框。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + N</td><td style="text-align:center;">打开文件查询框。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Alt + Shift + N</td><td style="text-align:center;">打开文本查询框。</td></tr><tr><td style="text-align:center;">Alt + 右箭头/左箭头</td><td style="text-align:center;">跳到下一个/上一个编辑器标签。</td></tr><tr><td style="text-align:center;">F12</td><td style="text-align:center;">如果当前在编辑窗口，触发后，会跳到之前操作过的工具栏上。</td></tr><tr><td style="text-align:center;">ESC</td><td style="text-align:center;">从工具栏上，再跳回原来的编辑窗口，一般与 F12 配合使用。</td></tr><tr><td style="text-align:center;">Shift + ESC</td><td style="text-align:center;">隐藏最后一个处于活跃状态的工具窗口。</td></tr><tr><td style="text-align:center;">Ctrl + Shift + F4</td><td style="text-align:center;">同时关闭处于活动状态的某些工具栏窗口。</td></tr><tr><td style="text-align:center;">Ctrl + G</td><td style="text-align:center;">跳转至某一行代码。。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + E</td><td style="text-align:center;">打开曾经操作过的文件历史列表。</td></tr><tr><td style="text-align:center;">Ctrl + Alt + 右箭头/左箭头</td><td style="text-align:center;">在曾经浏览过的代码行中来回跳</td></tr><tr><td style="text-align:center;">Ctrl + Shift + Backspace</td><td style="text-align:center;">跳转到最近的编辑位置（如果曾经编辑过代码）。</td></tr><tr><td style="text-align:center;">Alt + F1</td><td style="text-align:center;">打开一个类型列表，选择后会导航到当前文件或者内容的具体与类型相关的面板中。</td></tr><tr><td style="text-align:center;">Ctrl + B 或 Ctrl + 鼠标左键</td><td style="text-align:center;">如果是类，那么会跳转到当前光标所在的类定义或者接口；如果是变量，会打开一个变量被引用的列表。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Alt + B</td><td style="text-align:center;">跳转到实现类，而不是接口。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + I</td><td style="text-align:center;">打开一个面板，里面包含类代码。</td></tr><tr><td style="text-align:center;">Ctrl + Shift + B</td><td style="text-align:center;">打开变量的类型所对应的类代码，只对变量有用。</td></tr><tr><td style="text-align:center;">Ctrl + U</td><td style="text-align:center;">打开方法的超类方法或者类的超类，只对有超类的方法或者类有效。</td></tr><tr><td style="text-align:center;">Alt + 上/下箭头</td><td style="text-align:center;">在某个类中，跳到上一个/下一个方法的签名上。</td></tr><tr><td style="text-align:center;">Ctrl + ]/[</td><td style="text-align:center;">移动光标到类定义的终止右大括号或者起始左大括号。</td></tr><tr><td style="text-align:center;">Ctrl + F12</td><td style="text-align:center;">打开类的结构列表。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + H</td><td style="text-align:center;">打开类的继承关系列表。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + Shift + H</td><td style="text-align:center;">打开某个类方法的继承关系列表。</td></tr><tr><td style="text-align:center;">Ctrl + Alt + H</td><td style="text-align:center;">打开所有类的方法列表，这些方法都调用了当前光标所处的某个类方法。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">F2/Shift + F2</td><td style="text-align:center;">在编译错误的代码行中来回跳。</td></tr><tr><td style="text-align:center;">F4</td><td style="text-align:center;">打开当前光标所在处的方法或类源码。</td></tr><tr><td style="text-align:center;">Alt + Home</td><td style="text-align:center;">激活包路径的导航栏。</td></tr><tr><td style="text-align:center;">F11</td><td style="text-align:center;">把光标所处的代码行添加为书签或者从书签中删除。<span style="color:red;"><strong>（常用）</strong></span></td></tr><tr><td style="text-align:center;">Ctrl + F11</td><td style="text-align:center;">把光标所处的代码行添加为带快捷键的书签或者从快捷键书签中删除。</td></tr><tr><td style="text-align:center;">Ctrl + [0-9]</td><td style="text-align:center;">跳转到之前定义的快捷键书签。</td></tr><tr><td style="text-align:center;">Shift + F11</td><td style="text-align:center;">打开书签列表。<span style="color:red;"><strong>（常用）</strong></span></td></tr></tbody></table><blockquote><p>6.1 Ctrl + N （打开类查询框）</p></blockquote><p>键入类名的关键字，会自动出现相关的类哦，右侧还有一个勾选项，能够把引用的 jar 包中的类也加进来，很强大 O(∩_∩)O~ <img src="/intellij/1589727046696.jfif" alt=""></p><blockquote><p>6.2 Ctrl + Alt + 右箭头/左箭头（在曾经浏览过的代码行中来回跳）</p></blockquote><p>如果操作系统装的是 NVIDIA 显卡驱动程序，那么触发这个热键，会把旋转显示内容，而不是触发 idea 的功能，因为 idea 热键被 NVIDIA 显卡驱动给劫持咯。 解决方法是禁用 NVIDIA 显卡驱动所有快捷键，：</p><ul><li>1、控制面板-》显示-》屏幕分辨率：* <img src="/intellij/1589727066531.jfif" alt=""></li><li>2、点击【高级设置】-》核芯显卡控制面板：* <img src="/intellij/1589727077129.jfif" alt=""></li><li>3、图形属性-》选项与支持-》禁用所有快捷键（这些快捷键几乎没有什么用处！）* <img src="/intellij/1589727098644.jfif" alt=""></li></ul><blockquote><p>6.3 Alt + F1（打开一个类型列表）</p></blockquote><p><img src="/intellij/1589727122757.jfif" alt=""></p><blockquote><p>6.4 F11（添加为书签或者从书签中删除）</p></blockquote><p>书签不是默认视图，所以我们要把它添加到当前视图中：View -&gt; Tool Windows -&gt; Favorites，打开 Favorites 面板： <img src="/intellij/1589727139730.jfif" alt=""> Favorites 面板中的 Bookmarks 就是我们添加的书签哦： <img src="/intellij/1589727150856.jfif" alt=""> 或者直接使用 Shift + F11，打开书签列表也可以的哦 O(∩_∩)O~。</p><blockquote><p>6.5 Ctrl + F11 （添加或删除带快捷键的书签）</p></blockquote><p>会打开一个设置快捷键的面板，比如这里点击了 1，那么它的快捷键就是 Ctrl + 1。</p><p>注意不要选择面板提供的 26 个大写字母，因为这会与 idea 的其他快捷键冲突，不知道 idea 为什么要把它们放在这里？好奇怪 O(∩_∩)O~ <img src="/intellij/1589727177989.jfif" alt=""></p>',55),f={render:function(t,e){const l=(0,r.up)("OutboundLink");return(0,r.wg)(),(0,r.j4)(r.HY,null,[n,d,s,(0,r.Wm)("p",null,[a,(0,r.Wm)("a",i,[c,(0,r.Wm)(l)])]),(0,r.Wm)("p",null,[g,o,y,(0,r.Wm)("a",x,[p,(0,r.Wm)(l)])]),h],64)}}}}]);